+    // --- Player far outside map ---
+
+    #[test]
+    fn render_player_outside_map() {
+        let map = make_simple_map();
+        let mut renderer = DoomRenderer::new(40, 30);
+        let mut fb = DoomFramebuffer::new(40, 30);
+        let player = Player {
+            x: 10000.0,
