+    // --- High light level clamping ---
+
+    #[test]
+    fn high_light_level_clamped() {
+        use super::super::map::*;
+        // Sector with light_level > 255 should be clamped
+        let sectors = [Sector {
+            floor_height: 0.0,
+            ceiling_height: 128.0,
+            floor_texture: "FLOOR".into(),
+            ceiling_texture: "CEIL".into(),
+            light_level: 999, // Exceeds u8 range
+            special: 0,
+            tag: 0,
+        }];
