+    // --- Clip near plane preserves vertices already in front ---
+
+    #[test]
+    fn clip_near_plane_preserves_far_vertices() {
+        let (x1, y1, x2, y2) = clip_near_plane(100.0, 50.0, 200.0, -50.0);
