+            PackedRgba::rgb(0, 0, 0),
+            PackedRgba::rgb(255, 0, 0),
+            PackedRgba::rgb(0, 255, 0),
+            PackedRgba::rgb(0, 0, 255),
+        ];
+        // t=1/6 is midpoint between stop 0 and stop 1
+        let c = gradient_color(&stops, 1.0 / 6.0);
